// src/components/AudioUpload.js
import React, { useState } from "react";
import axios from "axios";

function AudioUpload() {
  const [audioFile, setAudioFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [uploadSuccess, setUploadSuccess] = useState(null);
  const [errorMessage, setErrorMessage] = useState("");

  // Function to handle file input change
  const handleFileChange = (e) => {
    setAudioFile(e.target.files[0]);
  };

  // Function to handle the file upload
  const handleUpload = async () => {
    if (!audioFile) {
      alert("Please select an audio file.");
      return;
    }

    const formData = new FormData();
    formData.append("audio", audioFile); // Add the audio file to FormData

    setUploading(true); // Set uploading state to true
    setErrorMessage(""); // Clear any previous error message
    setUploadSuccess(null); // Clear any previous success message

    try {
      const response = await axios.post("http://localhost:5001/upload", formData, {
        headers: {
          "Content-Type": "multipart/form-data", // Ensure the correct content type is set
        },
      });

      console.log("Server response:", response.data); // Log the response from the server

      if (response.data.message === "Audio file uploaded successfully!") {
        setUploadSuccess(true);
      } else {
        setUploadSuccess(false);
      }
    } catch (error) {
      console.error("Error uploading file:", error.response?.data || error.message);
      setUploadSuccess(false);
      setErrorMessage("Failed to upload audio.");
    } finally {
      setUploading(false); // Reset uploading state
    }
  };

  return (
    <div className="audio-upload-container" style={containerStyle}>
      <h1>Upload Audio File</h1>
      <input
        type="file"
        onChange={handleFileChange}
        accept="audio/*"
        style={inputStyle}
      />
      <button onClick={handleUpload} disabled={uploading} style={buttonStyle}>
        {uploading ? "Uploading..." : "Upload"}
      </button>

      {uploadSuccess !== null && (
        <div style={responseMessageStyle}>
          {uploadSuccess ? (
            <p style={successMessageStyle}>Audio uploaded successfully!</p>
          ) : (
            <p style={errorMessageStyle}>{errorMessage || "Failed to upload audio."}</p>
          )}
        </div>
      )}
    </div>
  );
}

// Styles for the components
const containerStyle = {
  textAlign: "center",
  marginTop: "50px",
};

const inputStyle = {
  margin: "10px 0",
};

const buttonStyle = {
  backgroundColor: "#4CAF50",
  color: "white",
  padding: "10px 20px",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer",
};

const responseMessageStyle = {
  marginTop: "20px",
};

const successMessageStyle = {
  color: "green",
  fontSize: "18px",
};

const errorMessageStyle = {
  color: "red",
  fontSize: "18px",
};

export default AudioUpload;
